#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,MX=5e6+10;
struct SEG{int l,r,sm;}t[N*50];int Rt[N],n,m,fa[N],cnt,a[N],loc[N],siz[N];
inline int find(int x){return fa[x]==x?x:fa[x]=find(fa[x]);}
inline bool Get(){char ch=getchar();while(ch^'Q'&&ch^'B')ch=getchar();return ch=='Q';}
inline void update(int k){t[k].sm=t[t[k].l].sm+t[t[k].r].sm;}
inline int merge(int x,int y,int l=1,int r=n)
{
//	printf("%d %d\n",x,y);
	if(!x||!y)return x|y;int mid=(l+r)>>1;
	t[x].l=merge(t[x].l,t[y].l,l,mid);t[x].r=merge(t[x].r,t[y].r,mid+1,r);update(x);return x;
}
inline void add(int &cur,int pos,int l=1,int r=n)
{
	if(!cur)cur=++cnt;if(l==r){t[cur].sm=1;return;}int mid=(l+r)>>1;
	pos<=mid?add(t[cur].l,pos,l,mid):add(t[cur].r,pos,mid+1,r);update(cur);
}
inline int fnd(int cur,int k,int l=1,int r=n)
{
	if(!cur)return -1;if(l==r)return l;int mid=(l+r)>>1;
	return t[t[cur].l].sm>=k?fnd(t[cur].l,k,l,mid):fnd(t[cur].r,k-t[t[cur].l].sm,mid+1,r);
}
int main()
{
	n=read(),m=read();rep(1,n,i)loc[a[i]=read()]=i;rep(1,n,i)add(Rt[i],a[fa[i]=i]);
	rep(1,m,i){int u=find(read()),v=find(read());if(u^v)fa[v]=u,Rt[u]=merge(Rt[u],Rt[v]);}
//	Rt[1]=merge(Rt[1],Rt[4]);Rt[1]=merge(Rt[1],Rt[2]);
//	printf("QUER %d %d %d\n",fnd(Rt[1],1),fnd(Rt[1],2),fnd(Rt[1],3));
//	
	
	int Q=read();while(Q--)
	{
		int u,v;switch(Get())
		{
			case 0: 
			{
				u=find(read());v=find(read());if(u==v)break;
				Rt[u]=merge(Rt[u],Rt[v]);fa[v]=u;break; 
			}
			case 1:u=find(read());v=fnd(Rt[u],read());
					printf("%d\n",~v?loc[v]:-1);break;
		}
//		rep(1,n,i)printf("%d ",Rt[i]);puts("");
//		rep(1,cnt,i)printf("%d :: %d %d %d\n",i,t[i].l,t[i].r,t[i].sm);
	}
}
